const _IMG = "data:image/png;base64,";

export function createGlobeDecoration() {
  const NS  = "http://www.w3.org/2000/svg";
  const svg = document.createElementNS(NS, "svg");
  svg.setAttribute("viewBox", "0 0 420 420");
  svg.setAttribute("width",  "400");
  svg.setAttribute("height", "400");
  svg.setAttribute("aria-hidden", "true");
  svg.style.cssText = "max-width:100%;display:block;margin:0 auto;overflow:visible;";
  const R = 175, CX = 210, CY = 210;
  svg.innerHTML = [
    "<defs>",
    "  <radialGradient id=\"sg\" cx=\"32%\" cy=\"24%\" r=\"42%\">",
    "    <stop offset=\"0%\"   stop-color=\"rgba(255,255,255,0.55)\"/>",
    "    <stop offset=\"30%\"  stop-color=\"rgba(255,255,255,0.10)\"/>",
    "    <stop offset=\"100%\" stop-color=\"rgba(255,255,255,0)\"/>",
    "  </radialGradient>",
    "  <radialGradient id=\"vg\" cx=\"50%\" cy=\"50%\" r=\"50%\">",
    "    <stop offset=\"72%\"  stop-color=\"rgba(0,0,0,0)\"/>",
    "    <stop offset=\"100%\" stop-color=\"rgba(10,28,55,0.30)\"/>",
    "  </radialGradient>",
    "  <clipPath id=\"gc\"><circle cx=\"" + CX + "\" cy=\"" + CY + "\" r=\"" + R + "\"/></clipPath>",
    "  <filter id=\"sf\"><feGaussianBlur stdDeviation=\"12\"/></filter>",
    "</defs>",
    "<ellipse cx=\"" + (CX+4) + "\" cy=\"" + (CY+R+18) + "\" rx=\"" + Math.round(R*0.74) + "\" ry=\"" + Math.round(R*0.08) + "\" fill=\"rgba(20,45,80,0.18)\" filter=\"url(#sf)\"/>",
    "<image href=\"" + _IMG + "\" x=\"" + (CX-R) + "\" y=\"" + (CY-R) + "\" width=\"" + (R*2) + "\" height=\"" + (R*2) + "\" preserveAspectRatio=\"xMidYMid meet\"/>",
    "<circle cx=\"" + CX + "\" cy=\"" + CY + "\" r=\"" + R + "\" fill=\"url(#vg)\" clip-path=\"url(#gc)\"/>",
    "<circle cx=\"" + CX + "\" cy=\"" + CY + "\" r=\"" + R + "\" fill=\"url(#sg)\" clip-path=\"url(#gc)\"/>",
  ].join("\n");
  return svg;
}